function htmlEscape(text) {
  return String(text || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

const item = $input.first().json || {};
const staticData = $getWorkflowStaticData('global');
const isDbError = !!(item.error && typeof item.error === 'object' && item.error.message);

if (isDbError) {
  return [{
    json: {
      report: '\u{1F534} <b>DATA RETENTION \u2014 DB ERROR</b>\n\nCleanup query failed.\n\n<b>Error:</b> <code>' + htmlEscape(String(item.error.message).substring(0, 500)) + '</code>\n<b>Timestamp:</b> ' + new Date().toISOString(),
      isDbError: true,
      isLimitHit: false,
      deletedEvents: 0,
      totalEvents: 0,
      eventsTableSize: 'unknown',
      eventsTableSizeBytes: 0,
      staleCircuitReset: false,
      schemaVersionPresent: false,
      expectedTablesFound: 0,
      schemaOk: false,
      shouldNotify: true,
      notifyReason: 'db_error'
    }
  }];
}

const deletedEvents = parseInt(item.deleted_events_count, 10) || 0;
const staleCircuitReset = item.stale_circuit_reset === true || item.stale_circuit_reset === 't';
const isLimitHit = deletedEvents >= 1000;
const totalEvents = parseInt(item.total_events, 10) || 0;
const eventsTableSize = item.events_table_size || 'unknown';
const eventsTableSizeBytes = parseInt(item.events_table_size_bytes, 10) || 0;
const schemaVersionPresent = (parseInt(item.schema_version_present, 10) || 0) > 0;
const expectedTablesFound = parseInt(item.expected_tables_found, 10) || 0;
const schemaOk = schemaVersionPresent && expectedTablesFound === 3;

const tableSizeThresholdBytes = 50 * 1024 * 1024;
const tableSizeWarning = eventsTableSizeBytes > tableSizeThresholdBytes;

const now = Date.now();
const lastReportAt = staticData.lastRetentionReportAt || 0;
const daysSinceLastReport = (now - lastReportAt) / (1000 * 60 * 60 * 24);
const weeklyReportDue = daysSinceLastReport >= 7;

let shouldNotify = false;
let notifyReason = 'routine_silent';

if (isDbError) { shouldNotify = true; notifyReason = 'db_error'; }
else if (!schemaOk) { shouldNotify = true; notifyReason = 'schema_drift'; }
else if (isLimitHit) { shouldNotify = true; notifyReason = 'limit_hit'; }
else if (staleCircuitReset) { shouldNotify = true; notifyReason = 'stale_circuit_reset'; }
else if (tableSizeWarning) { shouldNotify = true; notifyReason = 'table_size_warning'; }
else if (weeklyReportDue) { shouldNotify = true; notifyReason = 'weekly_summary'; }

let report = '\u{1F9F9} <b>DATA RETENTION REPORT \u2014 V1 Lean</b>\n\n'
  + '<b>Deleted Events (90d):</b> ' + deletedEvents + '\n'
  + '<b>Remaining Events:</b> ' + totalEvents + '\n'
  + '<b>Events Table Size:</b> ' + eventsTableSize + '\n'
  + '<b>Schema:</b> ' + (schemaOk ? '\u2705 v1_lean present, 3/3 tables' : '\u26A0\uFE0F check needed \u2014 version: ' + (schemaVersionPresent ? 'yes' : 'no') + ', tables: ' + expectedTablesFound + '/3');

if (staleCircuitReset) {
  report += '\n\n\u26A0\uFE0F <b>STALE CIRCUIT RESET:</b> Circuit was open for &gt;1 hour with no new errors. Auto-reset to closed.';
}

if (isLimitHit) {
  report += '\n\n\u26A0\uFE0F <b>LIMIT HIT:</b> Events table hit the 1000-row deletion cap. Run retention again if backlog persists.';
}

if (tableSizeWarning) {
  report += '\n\n\u26A0\uFE0F <b>TABLE SIZE WARNING:</b> supervisor_events is ' + eventsTableSize + ' (threshold: 50 MB).';
}

if (weeklyReportDue && !staleCircuitReset && !isLimitHit && !tableSizeWarning && schemaOk) {
  report += '\n\n\u{1F4C5} <i>Weekly scheduled report \u2014 no issues detected.</i>';
}

return [{
  json: {
    report: report,
    isDbError: false,
    isLimitHit: isLimitHit,
    deletedEvents: deletedEvents,
    totalEvents: totalEvents,
    eventsTableSize: eventsTableSize,
    eventsTableSizeBytes: eventsTableSizeBytes,
    staleCircuitReset: staleCircuitReset,
    schemaVersionPresent: schemaVersionPresent,
    expectedTablesFound: expectedTablesFound,
    schemaOk: schemaOk,
    tableSizeWarning: tableSizeWarning,
    shouldNotify: shouldNotify,
    notifyReason: notifyReason
  }
}];

function htmlEscape(text) {
  return String(text || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

const item = $input.first().json || {};
const evalData = (() => {
  try { return $('Evaluate Cleanup').first().json || {}; } catch(e) { return {}; }
})();

let report = evalData.report || '\u{1F9F9} <b>DATA RETENTION REPORT</b>\n\nNo cleanup report was generated.';
const analyzeError = !!(item.error && typeof item.error === 'object' && item.error.message);

if (analyzeError) {
  report += '\n\n\u26A0\uFE0F <b>ANALYZE FAILED:</b> <code>' + htmlEscape(String(item.error.message).substring(0, 500)) + '</code>';
} else {
  report += '\n\n\u2705 <b>ANALYZE:</b> completed successfully.';
}

report += '\n\n<b>Timestamp:</b> ' + new Date().toISOString();

let shouldNotify = evalData.shouldNotify || false;
let notifyReason = evalData.notifyReason || 'routine_silent';

if (analyzeError && !shouldNotify) {
  shouldNotify = true;
  notifyReason = 'analyze_failed';
}

return [{
  json: {
    ...evalData,
    report: report,
    analyzeOk: !analyzeError,
    analyzeErrorMessage: analyzeError ? item.error.message : '',
    shouldNotify: shouldNotify,
    notifyReason: notifyReason
  }
}];

const staticData = $getWorkflowStaticData('global');
const evalData = (() => {
  try { return $('Check Analyze Result').first().json || {}; } catch(e) { return {}; }
})();

if (evalData.shouldNotify) {
  staticData.lastRetentionReportAt = Date.now();
}

return [{ json: { done: true, notified: evalData.shouldNotify || false, notifyReason: evalData.notifyReason || 'silent' } }];

const staticData = $getWorkflowStaticData('global');
const item = $input.first().json || {};
if (!staticData.eventFailures) staticData.eventFailures = [];
staticData.eventFailures.push({
  timestamp: new Date().toISOString(),
  traceId: item.traceId || 'unknown',
  eventType: 'alert_failed',
  source: 'Data Retention',
  workflowName: 'Data Retention',
  failedNode: item.failedNode || 'unknown',
  reason: item.error?.message || 'Telegram or Postgres delivery failed'
});
if (staticData.eventFailures.length > 50) {
  staticData.droppedCacheCount = (staticData.droppedCacheCount || 0) + (staticData.eventFailures.length - 50);
  staticData.eventFailures = staticData.eventFailures.slice(-50);
}
return [{ json: { cached: true, count: staticData.eventFailures.length, droppedCacheCount: staticData.droppedCacheCount || 0 } }];
